package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor;
import org.eclipse.rdf4j.query.algebra.helpers.collectors.VarNameCollector;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbSketchAwareFilterPlacementTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String LIBRARY = "http://example.com/theme/library/";
	private static final IRI RDF_TYPE = VF.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
	private static final IRI COPY = VF.createIRI(LIBRARY, "Copy");
	private static final IRI LOCATED_AT = VF.createIRI(LIBRARY, "locatedAt");
	private static final IRI NAME = VF.createIRI(LIBRARY, "name");

	@Test
	void optimizedQueryKeepsBranchNameFilterAboveSelectiveJoinWhenSketchesReady(@TempDir File dataDir)
			throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig());
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadLibraryData(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuildOnceSlow();

			String query = String.join("\n",
					"PREFIX lib: <http://example.com/theme/library/>",
					"SELECT (COUNT(DISTINCT ?copy) AS ?count) WHERE {",
					"  ?branch lib:name ?branchName .",
					"  ?copy a lib:Copy .",
					"  ?copy lib:locatedAt ?branch .",
					"  FILTER ((?branchName = \"Branch 0\") || (?branchName = \"Branch 1\"))",
					"  FILTER EXISTS {",
					"    ?copy a lib:Copy .",
					"  }",
					"  MINUS {",
					"    ?copy lib:locatedAt ?branch .",
					"    FILTER (CONTAINS(STR(?branch), \"branch/0\"))",
					"  }",
					"}");

			TupleExpr optimized;
			try (SailRepositoryConnection connection = repository.getConnection()) {
				Explanation explanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized);
				optimized = (TupleExpr) explanation.tupleExpr();
			}

			Filter branchNameFilter = findBranchNameFilter(optimized);
			assertNotNull(branchNameFilter, "Expected optimized plan to retain the branch-name filter");
			assertTrue(branchNameFilter.getArg().getBindingNames().contains("copy"),
					"Branch-name filter should stay above the selective copy join when sketch estimation is ready");
		} finally {
			repository.shutDown();
		}
	}

	private static Filter findBranchNameFilter(TupleExpr optimized) {
		List<Filter> matches = new ArrayList<>(1);
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter node) {
				if (matches.isEmpty() && VarNameCollector.process(node.getCondition()).contains("branchName")) {
					matches.add(node);
				}
				super.meet(node);
			}
		});
		return matches.isEmpty() ? null : matches.get(0);
	}

	private static void loadLibraryData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);

			List<Resource> branches = new ArrayList<>(100);
			for (int i = 0; i < 100; i++) {
				Resource branch = VF.createIRI("urn:test:branch:" + i);
				branches.add(branch);
				connection.add(branch, NAME, VF.createLiteral("Branch " + i));
			}

			for (int i = 0; i < 40; i++) {
				Resource copy = VF.createIRI("urn:test:copy:" + i);
				Resource branch = branches.get(i % 2);
				connection.add(copy, RDF_TYPE, COPY);
				connection.add(copy, LOCATED_AT, branch);
			}

			for (int i = 0; i < 50; i++) {
				Resource noise = VF.createIRI("urn:test:noise:" + i);
				connection.add(noise, LOCATED_AT, branches.get(2 + (i % 20)));
			}

			connection.commit();
		}
	}
}
